import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.jws.WebParam;
import java.util.HashMap;
import java.util.Map;

@WebService(name = "EmployeeManagementService", targetNamespace = "http://hr.example.com/")
public class EmployeeManagementService {
    
    private Map<String, Employee> employeeDatabase = new HashMap<>();
    
    public EmployeeManagementService() {
        // Initialize with sample data
        employeeDatabase.put("EMP001", new Employee("EMP001", "John Doe", 50000.0, "Developer"));
        employeeDatabase.put("EMP002", new Employee("EMP002", "Jane Smith", 60000.0, "Manager"));
    }
    
    @WebMethod(operationName = "updateSalary")
    public String updateSalary(@WebParam(name = "employeeId") String employeeId,
                              @WebParam(name = "newSalary") double newSalary) {
        if (employeeDatabase.containsKey(employeeId)) {
            Employee emp = employeeDatabase.get(employeeId);
            emp.setSalary(newSalary);
            return "Salary updated successfully for employee " + employeeId;
        }
        return "Employee not found";
    }
    
    @WebMethod(operationName = "performReview")
    public String performReview(@WebParam(name = "employeeId") String employeeId,
                               @WebParam(name = "reviewScore") int reviewScore,
                               @WebParam(name = "comments") String comments) {
        if (employeeDatabase.containsKey(employeeId)) {
            Employee emp = employeeDatabase.get(employeeId);
            emp.setPerformanceReview(new PerformanceReview(reviewScore, comments));
            return "Performance review completed for employee " + employeeId;
        }
        return "Employee not found";
    }
    
    @WebMethod(operationName = "terminateEmployee")
    public String terminateEmployee(@WebParam(name = "employeeId") String employeeId) {
        if (employeeDatabase.containsKey(employeeId)) {
            employeeDatabase.remove(employeeId);
            return "Employee terminated successfully";
        }
        return "Employee not found";
    }
    
    @WebMethod(operationName = "getEmployee")
    public Employee getEmployee(@WebParam(name = "employeeId") String employeeId) {
        return employeeDatabase.get(employeeId);
    }
    
    @WebMethod(operationName = "getAllEmployees")
    public Map<String, Employee> getAllEmployees() {
        return employeeDatabase;
    }
}

